#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 7 (Layer 3, entrega 2): conv2 + pool2 + FC + argmax.
#   conv2: 8->16 canales 8x8 con DOS tiles de salida (bias recargado por tile)
#   pool2: maxpool 2x2 -> 16 canales 4x4
#   fc   : 256->10 con acumulador int32
#   argmax sobre el acumulador int32 (no sobre los logits requantizados)
# Criterio: TRES firmas por etapa identicas al oraculo
#   SIG_POOL2=0xA87E298C SIG_LOGITS=0xF7FF3389 SIG_CLASE=0x6084FD2A
# Requiere: ghdl 4.1.0 --std=08, python3. Requiere Pasos 1-3.
# Linea esperada al final:
# NPU PASO7 OK L3 SEQ_FULL PASS MUTACIONES 5/5 FAIL
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/model/npu_weights.hex" ] || [ ! -f "$DIR/rtl/npu_array.vhd" ]; then
  echo "FALLO: faltan Pasos 1-3 en $DIR"; exit 1
fi
mkdir -p "$DIR/rtl" "$DIR/tb" "$DIR/vec"
base64 -d << "EOF" > "$DIR/rtl/npu_seq_full.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_seq_full.vhd"

EOF
base64 -d << "EOF" > "$DIR/gen_l3_full.py"

EOF
base64 -d << "EOF" > "$DIR/run_l3_full.sh"

EOF
chmod +x "$DIR/run_l3_full.sh"
cd "$DIR"
bash run_l3_full.sh
)
